-- ===========================================================================
-- Benefit Market — Дополнительные сотрудники + массовые отзывы
-- ===========================================================================
-- Идемпотентный seed: ничего не удаляет, всё с ON CONFLICT / NOT EXISTS.
--
-- Добавляет в основной тенант:
--   • +15 сотрудников (UUID short_id 70..7e) с обязательными отчествами
--   • ~52 отзыва к 4 офферам провайдера BeneFit Studio (~13 на каждый)
--   • ~180 отзывов к 15 популярным офферам других провайдеров (~12 на каждый)
--
-- Никакие существующие сотрудники, отзывы и статусы офферов НЕ изменяются.
--
-- ЗАПУСК:
--   psql "$SUPABASE_DB_URL" -v ON_ERROR_STOP=1 -f supabase/seed_more_data.sql
-- Или через GitHub Actions: workflow «DB seed» с file=seed_more_data.sql.
-- ===========================================================================

CREATE EXTENSION IF NOT EXISTS pgcrypto;


-- ===========================================================================
-- БЛОК 1. +15 сотрудников в основном тенанте (UUID short_id 70..7e)
-- ===========================================================================

DO $more_employees$
DECLARE
  _tenant_id  uuid;
  _now        timestamptz := NOW();
  r           record;
  _user_id    uuid;
  _wallet_id  uuid;
  _hire_date  date;
  _cnt        int := 0;
BEGIN
  SELECT id INTO _tenant_id FROM tenants
   WHERE id != '00000000-0000-0000-0000-000000000000'
   ORDER BY created_at ASC LIMIT 1;

  IF _tenant_id IS NULL THEN
    RAISE EXCEPTION 'Основной тенант не найден. Сначала запустите seed.sql.';
  END IF;

  FOR r IN
    SELECT * FROM (VALUES
      ('70', 'Виктория Андреевна Захарова',      'viktoriya.zakharova',  'middle',   13, 17, 'Москва',          'ООО ТБ',                'Маркетинг',  'SMM-менеджер',                 'female', DATE '1993-05-21'),
      ('71', 'Григорий Петрович Назаров',        'grigoriy.nazarov',     'senior',   15, 42, 'Санкт-Петербург', 'ООО ТБ Северо-Запад',   'Разработка', 'DevOps-инженер',               'male',   DATE '1988-10-14'),
      ('72', 'Алина Юрьевна Тарасова',           'alina.tarasova',       'junior',   11,  6, 'Москва',          'ООО ТБ',                'Дизайн',     'Junior UI-дизайнер',           'female', DATE '2001-02-08'),
      ('73', 'Кирилл Александрович Богданов',    'kirill.bogdanov',      'middle',   13, 24, 'Казань',          'ООО ТБ',                'Разработка', 'Fullstack-разработчик',        'male',   DATE '1992-07-30'),
      ('74', 'Полина Игоревна Виноградова',      'polina.vinogradova',   'lead',     17, 55, 'Москва',          'ООО ТБ',                'Продукт',    'Продакт-лид',                  'female', DATE '1986-11-12'),
      ('75', 'Роман Сергеевич Кириллов',         'roman.kirillov',       'senior',   15, 36, 'Новосибирск',     'ООО ТБ Сибирь',         'QA',         'Senior QA-инженер',            'male',   DATE '1989-04-04'),
      ('76', 'Анастасия Дмитриевна Журавлёва',   'anastasia.zhuravleva', 'middle',   13, 15, 'Санкт-Петербург', 'ООО ТБ Северо-Запад',   'Аналитика',  'Бизнес-аналитик',              'female', DATE '1994-09-26'),
      ('77', 'Евгений Викторович Климов',        'evgeniy.klimov',       'junior',   11,  9, 'Москва',          'ООО ТБ',                'Поддержка',  'Специалист поддержки L1',      'male',   DATE '2000-12-03'),
      ('78', 'Маргарита Сергеевна Гусева',       'margarita.guseva',     'senior',   15, 46, 'Москва',          'ООО ТБ',                'HR',         'HR Business Partner',          'female', DATE '1987-06-19'),
      ('79', 'Станислав Александрович Шестаков', 'stanislav.shestakov',  'lead',     17, 58, 'Екатеринбург',    'ООО ТБ Урал',           'Разработка', 'Тимлид мобильной разработки',  'male',   DATE '1985-03-28'),
      ('7a', 'Валерия Петровна Беляева',         'valeriya.belyaeva',    'middle',   13, 21, 'Москва',          'ООО ТБ',                'Финансы',    'Финансовый аналитик',          'female', DATE '1991-08-15'),
      ('7b', 'Тимофей Олегович Громов',          'timofey.gromov',       'middle',   13, 27, 'Казань',          'ООО ТБ',                'Разработка', 'Backend Java-разработчик',     'male',   DATE '1992-02-10'),
      ('7c', 'Софья Михайловна Воробьёва',       'sofya.vorobieva',      'junior',   11,  4, 'Санкт-Петербург', 'ООО ТБ Северо-Запад',   'Маркетинг',  'Junior PR-менеджер',           'female', DATE '2001-10-07'),
      ('7d', 'Артур Дмитриевич Никитин',         'artur.nikitin',        'senior',   15, 38, 'Москва',          'ООО ТБ',                'Аналитика',  'Data Scientist',               'male',   DATE '1989-01-22'),
      ('7e', 'Алёна Игоревна Романова',          'alyona.romanova',      'director', 18, 72, 'Москва',          'ООО ТБ',                'Управление', 'Директор по разработке',       'female', DATE '1983-05-09')
    ) AS x(short_id, full_name, email_local, grade_text, grade_numeric, hire_months, location, legal_entity, department, position, gender, birthday)
  LOOP
    _user_id   := ('00000000-0000-4000-8000-0000000000' || r.short_id)::uuid;
    _wallet_id := ('00000000-0000-4000-8000-0000000003' || r.short_id)::uuid;
    _hire_date := (CURRENT_DATE - (r.hire_months || ' months')::interval)::date;

    INSERT INTO users (id, tenant_id, auth_id, email, role, full_name)
    VALUES (_user_id, _tenant_id, _user_id, r.email_local || '@techfuture.ru', 'employee'::user_role, r.full_name)
    ON CONFLICT DO NOTHING;

    IF NOT EXISTS (SELECT 1 FROM employee_profiles WHERE user_id = _user_id) THEN
      INSERT INTO employee_profiles (user_id, tenant_id, grade, grade_numeric, tenure_months, hire_date, location, legal_entity, gender, birthday, extra)
      VALUES (
        _user_id, _tenant_id,
        r.grade_text, r.grade_numeric, r.hire_months, _hire_date,
        r.location, r.legal_entity, r.gender, r.birthday,
        jsonb_build_object(
          'full_name',  r.full_name,
          'department', r.department,
          'position',   r.position,
          'work_format', CASE (r.hire_months % 3) WHEN 0 THEN 'office' WHEN 1 THEN 'hybrid' ELSE 'remote' END,
          'priorities', CASE r.department
                          WHEN 'Разработка' THEN ARRAY['education','health','subscriptions']
                          WHEN 'Дизайн'     THEN ARRAY['education','beauty','entertainment']
                          WHEN 'Финансы'    THEN ARRAY['health','family','travel']
                          WHEN 'Маркетинг'  THEN ARRAY['entertainment','beauty','sport']
                          WHEN 'Аналитика'  THEN ARRAY['education','health','subscriptions']
                          WHEN 'QA'         THEN ARRAY['education','health','entertainment']
                          WHEN 'Поддержка'  THEN ARRAY['health','sport','subscriptions']
                          WHEN 'HR'         THEN ARRAY['family','health','beauty']
                          WHEN 'Продукт'    THEN ARRAY['education','travel','entertainment']
                          WHEN 'Управление' THEN ARRAY['health','travel','family']
                          ELSE                   ARRAY['health','sport','entertainment']
                        END
        )
      );
    END IF;

    INSERT INTO wallets (id, user_id, tenant_id, balance, reserved, period, expires_at)
    VALUES (
      _wallet_id, _user_id, _tenant_id,
      CASE r.grade_text
        WHEN 'junior'   THEN 35000
        WHEN 'middle'   THEN 50000
        WHEN 'senior'   THEN 50000
        WHEN 'lead'     THEN 80000
        WHEN 'director' THEN 80000
      END,
      0,
      TO_CHAR(_now, 'YYYY') || '-Q' || CEIL(EXTRACT(MONTH FROM _now) / 3.0)::int,
      (DATE_TRUNC('quarter', _now) + INTERVAL '3 months')::timestamptz
    )
    ON CONFLICT DO NOTHING;

    _cnt := _cnt + 1;
  END LOOP;

  RAISE NOTICE 'БЛОК 1: обработано сотрудников: %', _cnt;
END $more_employees$;


-- ===========================================================================
-- БЛОК 2. Гарантировать существование BeneFit Studio + 4 offerings
-- ===========================================================================
-- Статусы офферов НЕ изменяются — оставляем как в seed_demo.sql.
-- Если провайдер и офферы уже есть — INSERT'ы тихо пропускаются.
-- ===========================================================================

DO $more_bm_studio$
DECLARE
  _tenant_id      uuid;
  _hr_owner       uuid;
  _bm_provider_id uuid;
BEGIN
  SELECT id INTO _tenant_id FROM tenants
   WHERE id != '00000000-0000-0000-0000-000000000000'
   ORDER BY created_at ASC LIMIT 1;

  SELECT id INTO _hr_owner FROM users
   WHERE tenant_id = _tenant_id ORDER BY created_at ASC LIMIT 1;

  IF _hr_owner IS NULL THEN
    RAISE NOTICE 'БЛОК 2: пропущен (в тенанте нет пользователей)';
    RETURN;
  END IF;

  INSERT INTO providers (owner_user_id, name, slug, description, status, contact_email, website, address, verified_at)
  VALUES (
    _hr_owner, 'BeneFit Studio', 'benefit-studio',
    'Студия партнёрских льгот. Wellness-программы, корпоративные мероприятия и онлайн-тренинги для сотрудников.',
    'verified'::provider_status, 'partner@bm.demo', 'https://benefit-studio.demo', 'Москва', NOW()
  )
  ON CONFLICT (slug) DO NOTHING;

  SELECT id INTO _bm_provider_id FROM providers WHERE slug = 'benefit-studio';

  -- Wellness — published
  INSERT INTO provider_offerings (provider_id, global_category_id, name, description, long_description, base_price_points, status, format, cities, delivery_info, terms_conditions, avg_rating, review_count)
  SELECT _bm_provider_id,
         (SELECT id FROM global_categories WHERE name = 'Здоровье'),
         'Wellness-программа «Энергия»',
         'Двухмесячная программа: персональный план питания, тренировки, медитации.',
         'Двухмесячная индивидуальная программа: разработка плана питания нутрициологом, тренировки 3 раза в неделю с тренером онлайн, ежедневные медитации, контрольные созвоны раз в неделю.',
         15000, 'published'::offering_status, 'online'::offering_format, ARRAY[]::text[],
         'Старт после знакомства с куратором',
         '60 дней с активации',
         4.7, 6
  WHERE NOT EXISTS (SELECT 1 FROM provider_offerings WHERE provider_id = _bm_provider_id AND name = 'Wellness-программа «Энергия»');

  -- Stress management — pending_review
  INSERT INTO provider_offerings (provider_id, global_category_id, name, description, long_description, base_price_points, status, format, cities, delivery_info, terms_conditions, avg_rating, review_count)
  SELECT _bm_provider_id,
         (SELECT id FROM global_categories WHERE name = 'Образование'),
         'Тренинг «Stress management» для команды',
         'Корпоративный тренинг по управлению стрессом и профилактике выгорания (4 часа).',
         'Очный или онлайн-тренинг для команды до 20 человек. Психолог-эксперт ведёт интерактивную программу с практиками. Получите чек-лист и план для команды.',
         8000, 'pending_review'::offering_status, 'online'::offering_format, ARRAY[]::text[],
         'Дата согласовывается с куратором',
         'Один тренинг на компанию',
         0, 0
  WHERE NOT EXISTS (SELECT 1 FROM provider_offerings WHERE provider_id = _bm_provider_id AND name = 'Тренинг «Stress management» для команды');

  -- Тимбилдинг — draft
  INSERT INTO provider_offerings (provider_id, global_category_id, name, description, long_description, base_price_points, status, format, cities, delivery_info, terms_conditions, avg_rating, review_count)
  SELECT _bm_provider_id,
         (SELECT id FROM global_categories WHERE name = 'Развлечения'),
         'Тимбилдинг «Квест в офисе»',
         'Корпоративный квест в офисе или на выезде. Команда до 50 человек.',
         'Командная игра с сюжетом: расследование, головоломки, актёры. Длительность 2-3 часа. Поможет сплотить команду и найти лидеров.',
         20000, 'draft'::offering_status, 'offline'::offering_format, ARRAY['Москва'],
         '',
         '',
         0, 0
  WHERE NOT EXISTS (SELECT 1 FROM provider_offerings WHERE provider_id = _bm_provider_id AND name = 'Тимбилдинг «Квест в офисе»');

  -- Йога — archived
  INSERT INTO provider_offerings (provider_id, global_category_id, name, description, long_description, base_price_points, status, format, cities, delivery_info, terms_conditions, avg_rating, review_count)
  SELECT _bm_provider_id,
         (SELECT id FROM global_categories WHERE name = 'Здоровье'),
         'Мини-курс «Йога для офиса»',
         'Архивный курс — 8 видеоуроков йоги по 15 минут.',
         'Короткие видеоуроки, которые можно делать прямо за рабочим столом. Снимают напряжение в шее, спине, запястьях.',
         2000, 'archived'::offering_status, 'online'::offering_format, ARRAY[]::text[],
         '',
         '',
         4.2, 3
  WHERE NOT EXISTS (SELECT 1 FROM provider_offerings WHERE provider_id = _bm_provider_id AND name = 'Мини-курс «Йога для офиса»');

  -- Wellness (единственный published) подключаем в каталог тенанта, если ещё нет
  INSERT INTO tenant_offerings (tenant_id, provider_offering_id, custom_price_points, is_active, enabled_by, enabled_at)
  SELECT _tenant_id, po.id, NULL, true, _hr_owner, NOW()
  FROM provider_offerings po
  WHERE po.provider_id = _bm_provider_id
    AND po.name = 'Wellness-программа «Энергия»'
  ON CONFLICT (tenant_id, provider_offering_id) DO NOTHING;

  RAISE NOTICE 'БЛОК 2: BeneFit Studio гарантирован';
END $more_bm_studio$;


-- ===========================================================================
-- БЛОК 3. ~52 отзыва к 4 офферам BeneFit Studio (~13 на каждый)
-- ===========================================================================
-- UNIQUE (user_id, provider_offering_id) защищает от дублей.
-- Используем сотрудников из всех диапазонов: 30..35, 40..4e, 70..7e.
-- ===========================================================================

DO $more_bm_reviews$
DECLARE
  _tenant_id uuid;
  r          record;
  _idx       int := 0;
  _cnt       int := 0;
BEGIN
  SELECT id INTO _tenant_id FROM tenants
   WHERE id != '00000000-0000-0000-0000-000000000000'
   ORDER BY created_at ASC LIMIT 1;

  FOR r IN
    SELECT u.id AS user_id, po.id AS po_id, val.rating, val.title, val.body
    FROM (VALUES
      -- ==================== Wellness-программа «Энергия» (13 отзывов) ====================
      ('00000000-0000-4000-8000-000000000030'::uuid, 'Wellness-программа «Энергия»', 5, 'Перезагрузил режим',                'Куратор пересмотрел завтраки, ушла утренняя сонливость. За 2 месяца сбросил 4 кг.'),
      ('00000000-0000-4000-8000-000000000031'::uuid, 'Wellness-программа «Энергия»', 5, 'Куратор пинает в чате',             'Это работает: меняет план, если выпадаю из графика. Впервые за 5 лет в форме.'),
      ('00000000-0000-4000-8000-000000000033'::uuid, 'Wellness-программа «Энергия»', 5, 'Тренировки в обед',                 'По 45 минут с тренером онлайн. Идеально укладываются в обед, не съедают вечер.'),
      ('00000000-0000-4000-8000-000000000034'::uuid, 'Wellness-программа «Энергия»', 5, 'Снова люблю утра',                  'Меню под низкоуглеводное — стал высыпаться, ушла дневная сонливость.'),
      ('00000000-0000-4000-8000-000000000035'::uuid, 'Wellness-программа «Энергия»', 4, 'Дисциплина обязательна',            'Программа отличная, но без созвонов с куратором легко выпасть из режима.'),
      ('00000000-0000-4000-8000-000000000040'::uuid, 'Wellness-программа «Энергия»', 5, 'Беру вторую программу',             'После первой захотелось продолжить. Меняет отношение к телу и питанию.'),
      ('00000000-0000-4000-8000-000000000041'::uuid, 'Wellness-программа «Энергия»', 5, 'DevOps восстанавливается',          'После релизов снимаю стресс через медитации из программы.'),
      ('00000000-0000-4000-8000-000000000043'::uuid, 'Wellness-программа «Энергия»', 4, 'Полезно, но требует времени',       'Часовые тренировки, нутрициолог раз в неделю. С плотным графиком сложно.'),
      ('00000000-0000-4000-8000-000000000044'::uuid, 'Wellness-программа «Энергия»', 5, 'Лидер берёт ресурс',                'Брала программу после квартального аврала. Восстановилась за месяц.'),
      ('00000000-0000-4000-8000-000000000070'::uuid, 'Wellness-программа «Энергия»', 4, 'Дорого без корпоративного бонуса',  'Если платить из своего — задумалась бы. С компенсацией — однозначно да.'),
      ('00000000-0000-4000-8000-000000000073'::uuid, 'Wellness-программа «Энергия»', 5, 'Fullstack получил старт',           'Сидячая работа — теперь два раза в неделю в зале. Программа дала разгон.'),
      ('00000000-0000-4000-8000-000000000078'::uuid, 'Wellness-программа «Энергия»', 5, 'HR рекомендует команде',            'Сама прошла — теперь раздаю ссылку коллегам как HR-инструмент.'),
      ('00000000-0000-4000-8000-00000000007d'::uuid, 'Wellness-программа «Энергия»', 4, 'Data Science нужно тело',           'После 8 часов за ноутом тренировки — must. Программа помогла стартовать.'),

      -- ==================== Тренинг «Stress management» для команды (13 отзывов) ====================
      ('00000000-0000-4000-8000-000000000030'::uuid, 'Тренинг «Stress management» для команды', 5, 'Quick-reset на дедлайнах',          'Применяю технику быстрого восстановления уже месяц. Реально помогает.'),
      ('00000000-0000-4000-8000-000000000032'::uuid, 'Тренинг «Stress management» для команды', 4, 'Хорошо, но нужен фоллоу-ап',        '4 часа быстро, через месяц забыл половину техник. Просим повторить.'),
      ('00000000-0000-4000-8000-000000000034'::uuid, 'Тренинг «Stress management» для команды', 5, 'Команда стала спокойнее',           'После тренинга быстрее проходим конфликты. Меньше эскалаций к лиду.'),
      ('00000000-0000-4000-8000-000000000035'::uuid, 'Тренинг «Stress management» для команды', 5, 'Корпоративная инвестиция',          'Окупается через снижение текучки. Сотрудники возвращаются более вовлечёнными.'),
      ('00000000-0000-4000-8000-000000000042'::uuid, 'Тренинг «Stress management» для команды', 5, 'Помогли с приоритезацией',          'Тренеры дают конкретные инструменты, не общие слова. Применяю каждый день.'),
      ('00000000-0000-4000-8000-000000000044'::uuid, 'Тренинг «Stress management» для команды', 4, 'Требует регулярной практики',       'Знания дают, но без практики не приживаются. Купили подписку на медитации.'),
      ('00000000-0000-4000-8000-000000000047'::uuid, 'Тренинг «Stress management» для команды', 5, 'Дыхание перед демо',                'Учусь дышать на созвонах. Перед демо использую — голос меньше дрожит.'),
      ('00000000-0000-4000-8000-000000000049'::uuid, 'Тренинг «Stress management» для команды', 5, 'От тушения пожаров к управлению',   'Раньше реагировал на стресс, теперь действую осознанно.'),
      ('00000000-0000-4000-8000-00000000004a'::uuid, 'Тренинг «Stress management» для команды', 5, 'HR взял в работу',                  'Заказала второй тренинг через месяц для другой команды.'),
      ('00000000-0000-4000-8000-000000000071'::uuid, 'Тренинг «Stress management» для команды', 4, 'DevOps incident-response',          'Помогает в инцидентах, но 4 часов мало для глубокой проработки.'),
      ('00000000-0000-4000-8000-000000000075'::uuid, 'Тренинг «Stress management» для команды', 5, 'Reset перед релизом',               'Применяю quick-reset перед стрессовыми релизами. Команда заметила разницу.'),
      ('00000000-0000-4000-8000-000000000077'::uuid, 'Тренинг «Stress management» для команды', 3, 'Хочется квартально',                'Раз в год недостаточно — забывается. Просим повторять каждые 3 месяца.'),
      ('00000000-0000-4000-8000-00000000007e'::uuid, 'Тренинг «Stress management» для команды', 5, 'Лидерам тоже нужно',                'Закрепили команду перед сложным проектом. Прошли спокойнее обычного.'),

      -- ==================== Тимбилдинг «Квест в офисе» (13 отзывов) ====================
      ('00000000-0000-4000-8000-000000000033'::uuid, 'Тимбилдинг «Квест в офисе»', 5, 'Лучший корпоратив за 3 года',     'Актёры включены, головоломки нестандартные. Не скучный конкурс — настоящая игра.'),
      ('00000000-0000-4000-8000-000000000034'::uuid, 'Тимбилдинг «Квест в офисе»', 5, 'Backend и Дизайн сработались',    'Впервые увидели коллег из других отделов с другой стороны.'),
      ('00000000-0000-4000-8000-000000000040'::uuid, 'Тимбилдинг «Квест в офисе»', 5, 'Маркетинг закрыл первым',         'Командные навыки проверили на практике. Команда сплотилась.'),
