      ('00000000-0000-4000-8000-000000000072'::uuid, 'Мини-курс «Йога для офиса»', 4, 'Junior-friendly',               'Не страшно начинать с нуля. Объясняют простым языком.'),
      ('00000000-0000-4000-8000-000000000074'::uuid, 'Мини-курс «Йога для офиса»', 5, 'Между созвонами',               'Делаю в 15-минутном гэпе перед митингом. Лучше любого кофе.'),
      ('00000000-0000-4000-8000-000000000077'::uuid, 'Мини-курс «Йога для офиса»', 4, 'Reset после тикетов',           'После 6 часов в саппорте — отличный способ переключиться.'),
      ('00000000-0000-4000-8000-000000000078'::uuid, 'Мини-курс «Йога для офиса»', 4, 'Архив, но актуально',           'Прохожу повторно, ничего не теряет в актуальности.'),
      ('00000000-0000-4000-8000-00000000007a'::uuid, 'Мини-курс «Йога для офиса»', 4, 'Финансисты тоже устают',        'После закрытия квартала — спасает шею и поясницу.'),
      ('00000000-0000-4000-8000-00000000007c'::uuid, 'Мини-курс «Йога для офиса»', 5, 'PR-команда переключается',      'После пресс-релиза — отличный способ переключиться между задачами.')
    ) AS val(user_id, po_name, rating, title, body)
    JOIN users u               ON u.id   = val.user_id
    JOIN provider_offerings po ON po.name = val.po_name
    WHERE u.tenant_id = _tenant_id
  LOOP
    INSERT INTO reviews (provider_offering_id, tenant_id, user_id, rating, title, body, status, created_at, updated_at)
    SELECT r.po_id, _tenant_id, r.user_id, r.rating, r.title, r.body,
           'visible'::review_status,
           NOW() - ((10 + ((_idx * 7) % 110)) || ' days')::interval,
           NOW() - ((10 + ((_idx * 7) % 110)) || ' days')::interval
    WHERE NOT EXISTS (
      SELECT 1 FROM reviews WHERE user_id = r.user_id AND provider_offering_id = r.po_id
    );
    _idx := _idx + 1;
    _cnt := _cnt + 1;
  END LOOP;

  RAISE NOTICE 'БЛОК 3: обработано отзывов BeneFit Studio: % (дубли пропущены)', _cnt;
END $more_bm_reviews$;


-- ===========================================================================
