      ('00000000-0000-4000-8000-000000000048'::uuid, 'Чекап ИНВИТРО Premium', 5, 'Финансы тоже за здоровье',      'Считала ROI — окупается выявленными проблемами на ранних стадиях.'),
      ('00000000-0000-4000-8000-00000000004a'::uuid, 'Чекап ИНВИТРО Premium', 5, 'HR-стандарт',                   'Беру каждый год. Команде советую — половина уже взяла.'),
      ('00000000-0000-4000-8000-00000000004d'::uuid, 'Чекап ИНВИТРО Premium', 5, 'BI-аналитик в графиках',        'Удобный отчёт — слежу за динамикой год к году. Профессиональная деформация.'),
      ('00000000-0000-4000-8000-000000000071'::uuid, 'Чекап ИНВИТРО Premium', 4, 'DevOps глянул внутрь',          'Холестерин повышен — корректирую питание. Без чекапа не узнал бы.'),
      ('00000000-0000-4000-8000-000000000076'::uuid, 'Чекап ИНВИТРО Premium', 5, 'Бизнес-аналитик ценит данные',  'Свои показатели — это тоже данные. Анализирую динамику год к году.'),
      ('00000000-0000-4000-8000-00000000007e'::uuid, 'Чекап ИНВИТРО Premium', 5, 'Директор инвестирует в себя',   'Раз в год — обязательно. Команда видит — берут тоже.')
    ) AS val(user_id, po_name, rating, title, body)
    JOIN users u               ON u.id   = val.user_id
    JOIN provider_offerings po ON po.name = val.po_name
    WHERE u.tenant_id = _tenant_id
  LOOP
    INSERT INTO reviews (provider_offering_id, tenant_id, user_id, rating, title, body, status, created_at, updated_at)
    SELECT r.po_id, _tenant_id, r.user_id, r.rating, r.title, r.body,
           'visible'::review_status,
           NOW() - ((5 + ((_idx * 11) % 180)) || ' days')::interval,
           NOW() - ((5 + ((_idx * 11) % 180)) || ' days')::interval
    WHERE NOT EXISTS (
      SELECT 1 FROM reviews WHERE user_id = r.user_id AND provider_offering_id = r.po_id
    );
    _idx := _idx + 1;
    _cnt := _cnt + 1;
  END LOOP;

  RAISE NOTICE 'БЛОК 4: обработано отзывов каталога: % (дубли и отсутствующие офферы пропущены)', _cnt;
END $more_catalog_reviews$;


-- ===========================================================================
-- БЛОК 5. Диагностика результата
-- ===========================================================================

DO $more_diag$
DECLARE
  _tenant_id    uuid;
  _users_count  int;
  _reviews_count int;
  _bm_count     int;
BEGIN
  SELECT id INTO _tenant_id FROM tenants
   WHERE id != '00000000-0000-0000-0000-000000000000'
   ORDER BY created_at ASC LIMIT 1;

  SELECT count(*) INTO _users_count   FROM users WHERE tenant_id = _tenant_id;
  SELECT count(*) INTO _reviews_count FROM reviews WHERE tenant_id = _tenant_id;
  SELECT count(*) INTO _bm_count      FROM reviews r
    JOIN provider_offerings po ON po.id = r.provider_offering_id
    JOIN providers pr          ON pr.id = po.provider_id
    WHERE pr.slug = 'benefit-studio';

  RAISE NOTICE '======================================';
  RAISE NOTICE 'ИТОГИ seed_more_data.sql:';
  RAISE NOTICE '  Пользователей в тенанте: %',  _users_count;
  RAISE NOTICE '  Отзывов всего в тенанте: %',  _reviews_count;
  RAISE NOTICE '  Отзывов на BeneFit Studio: %', _bm_count;
  RAISE NOTICE '======================================';
END $more_diag$;
